import Navbar from "@/components/Navbar";
import Footer from "@/components/Footer";
import Hero from "@/components/landing/Hero";
import About from "@/components/landing/About";
import FeaturedBlogs from "@/components/landing/FeaturedBlogs";
import Topics from "@/components/landing/Topics";
import Newsletter from "@/components/landing/Newsletter";
import { sanityFetch } from "@/sanity/lib/fetch";
import { postsQuery, authorQuery } from "@/sanity/lib/queries";

export default async function Home() {
    const [allPosts, author] = await Promise.all([
        sanityFetch<any[]>({ query: postsQuery }),
        sanityFetch<any>({ query: authorQuery }),
    ]);
    const featuredPosts = allPosts.slice(0, 3); // Just take the latest 3 as featured

    return (
        <>
            <Navbar />
            <main className="min-h-screen">
                <Hero />
                <FeaturedBlogs blogs={featuredPosts} />
                <About author={author} />
                <Topics />
                <Newsletter />
            </main>
            <Footer />
        </>
    );
}
